// src/api/chatApi.js - HTTP Only (No Socket)
import axios from "axios";
const API_BASE_URL = "https://capavate.com/";

const API_URL = `${API_BASE_URL}api/user/chatmessage`;

// ==================== API CALLS ONLY (NO SOCKET) ====================

// Get or create conversation
export const getOrCreateConversation = async (
  participant1_type,
  participant1_id,
  participant2_type,
  participant2_id,
) => {
  try {
    const response = await axios.post(`${API_URL}/get_or_create_conversation`, {
      participant1_type,
      participant1_id,
      participant2_type,
      participant2_id,
    });
    return response.data;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

// Get user conversations list
export const getUserConversations = async (user_type, user_id) => {
  try {
    const response = await axios.post(`${API_URL}/get-user-conversations`, {
      user_type,
      user_id,
    });
    return response.data;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

// Get messages for a conversation
export const getMessages = async (
  conversation_id,
  user_id,
  user_type,
  limit = 50,
  offset = 0,
) => {
  try {
    const response = await axios.post(`${API_URL}/get-messages`, {
      conversation_id,
      user_id,
      user_type,
      limit,
      offset,
    });
    return response.data;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

// Send message
export const sendMessage = async (
  conversation_id,
  sender_type,
  sender_id,
  receiver_type,
  receiver_id,
  message,
) => {
  try {
    const response = await axios.post(
      `${API_URL}/send-message`,
      {
        conversation_id,
        sender_type,
        sender_id,
        receiver_type,
        receiver_id,
        message,
      },
      {
        headers: { "Content-Type": "application/json" },
      },
    );

    return response.data;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

// Delete message
export const deleteMessage = async (message_id, user_id, user_type) => {
  try {
    const response = await axios.post(`${API_URL}/delete-message`, {
      message_id,
      user_id,
      user_type,
    });
    return response.data;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

// Upload file
export const uploadFile = async (formData) => {
  try {
    const response = await axios.post(`${API_URL}/upload-file`, formData, {
      headers: {
        "Content-Type": "multipart/form-data",
      },
    });
    return response.data;
  } catch (error) {
    console.error("Error:", error);
    throw error;
  }
};

// ==================== DUMMY SOCKET FUNCTIONS (No-op) ====================
export const initSocket = () => {
  console.log("Socket disabled - using HTTP only");
  return null;
};

export const getSocket = () => null;
export const disconnectSocket = () => {};
export const joinConversation = () => {};
export const leaveConversation = () => {};
export const emitTypingStart = () => {};
export const emitTypingEnd = () => {};
export const emitMarkAsRead = () => {};
export const onNewMessage = () => {};
export const onUserTyping = () => {};
export const onMessagesRead = () => {};
export const onUserStatusChange = () => {};
export const onMessageNotification = () => {};
export const removeAllListeners = () => {};
